import subprocess,base64,datetime,time,json,os,urllib.request
P1='192.168.10.19'
WEB='/var/www/html'
MP='/mnt/vnt-data/FileServer/VNT_World_AI_Division/MemPalace.md'
CFG='/mnt/vnt-data/FileServer/VNT_World_AI_Division/vnt_config.json'
TSF=datetime.datetime.now().strftime('%Y%m%d_%H%M')

PARTS=[
    b'',
    b'',
    b'',
    b'',
    b'',
    b'',
    b'',
    b'',
    b'',
    b'',
    b'',
    b'',
    b'',
    b'',
    b'',
    b'',
]
HTML=base64.b64decode(b''.join(PARTS))
print(f'[HTML] {len(HTML)} bytes ready')

def rx(h,c,t=30):
    r=subprocess.run(['ssh','-o','StrictHostKeyChecking=no','-o','ConnectTimeout=8','root@'+h,c],capture_output=True,text=True,timeout=t)
    return (r.stdout+r.stderr).strip()
def pct_e(id,c,t=60):
    r=subprocess.run(['ssh','-o','StrictHostKeyChecking=no','-o','ConnectTimeout=8','root@'+P1,'pct exec '+str(id)+' -- bash -c '+json.dumps(c)],capture_output=True,text=True,timeout=t)
    return (r.stdout+r.stderr).strip()
def save(e):
    try: open(MP,'a').write('\n### CT108 v3 ['+TSF+']\n'+e+'\n')
    except: pass

print('='*55)
print('DEPLOY CT108 DASHBOARD v3 - CLEAN STUDIO')
print(TSF)
print('='*55)

# Verify CT108
st=rx(P1,'pct status 108')
print('[1] CT108:',st)
if 'stopped' in st.lower():
    rx(P1,'pct start 108',t=20); time.sleep(8)

# BACKUP
print('[2] Backup...')
pct_e(108,f'cp {WEB}/dashboard.html {WEB}/dashboard.html.bak_{TSF} && echo OK')
os.makedirs('/root/ct108_backups',exist_ok=True)
rx(P1,f'pct pull 108 {WEB}/dashboard.html /root/ct108_backups/dash_{TSF}.html',t=20)
print('  Backup: /root/ct108_backups/dash_'+TSF+'.html')

# Write
print('[3] Writing v3 to CT108...')
open('/tmp/new_dash_v3.html','wb').write(HTML)
push_r=rx(P1,'pct push 108 /tmp/new_dash_v3.html '+WEB+'/dashboard.html',t=30)
print('  pct push:',push_r or 'OK')

# Verify
v=pct_e(108,f'wc -c {WEB}/dashboard.html')
g=pct_e(108,f'grep -c GAMES {WEB}/dashboard.html 2>/dev/null')
s=pct_e(108,f'grep -c spane-images {WEB}/dashboard.html 2>/dev/null')
print('[4] Size:',v,'| GAMES:',g,'| Studio tabs:',s)

# Nginx reload
nr=pct_e(108,'nginx -s reload 2>/dev/null || service nginx reload 2>/dev/null || echo reloaded')
print('[5] Nginx:',nr[:60])

# Update config
try:
    cfg=json.load(open(CFG))
except: cfg={}
cfg.update({'production_web_ct':'108','production_web_root':WEB,'production_domain':'vntworld.com','never_write_to':'/home/k/vnt-web','ct108_last_deploy':TSF,'ct108_version':'v3'})
json.dump(cfg,open(CFG,'w'),indent=2)

save('CT108 v3 deployed '+TSF+'\nStudio: Images/Videos/3Ds/Audios/2Ds ONLY\nGames/Apps/Desktop: in main sidebar\nBackup: '+WEB+'/dashboard.html.bak_'+TSF)
print('='*55)
print('DONE: vntworld.com/dashboard.html v3')
print('Studio now: Images | Videos | 3D Models | Audio | 2D Drawings')
print('Rollback: pct exec 108 -- bash -c "cp '+WEB+'/dashboard.html.bak_'+TSF+' '+WEB+'/dashboard.html"')
print('='*55)